mapper.sql:
SELECT M1.ID, M1.SHIP_NAME, M1.SHIP_NAME_EN, M1.SHORTHAND_CODE, M1.SHIP_KIND_CODE, E.DICT_LABEL AS SHIP_KIND_LABEL, M1.NATION_CODE, F.DICT_LABEL AS NATION_LABEL, M1.SHIP_TYPE_CODE, D.DICT_LABEL AS SHIP_TYPE_LABEL, M1.IMO, M1.MMSI, M1.CALL_NO, M1.SHIP_LENGTH, M1.SHIP_WIDTH, M1.SHIP_HEIGHT, M1.SELF_WEIGHT, M1.NET_WEIGHT, M1.TOTAL_WEIGHT, M1.HATCH_NUM, M1.CABIN_LAYER_NUM, M1.DWT, M1.CABIN_VOLUME, M1.HATCH_SIZE, M1.MAX_SPEED, M1.SPEED, M1.MOULDED_DEPTH, M1.HANGER_NUM, M1.CABIN_TYPE, M1.HANGER_LOAD, M1.HATCH_COVER_TYPE_CODE, M1.HANGER_LOCATION, M1.CAPTAIN_PHONE, M1.CAPTAIN_NAME, M1.BUILT_YM, M1.WATER_VOLUME, M1.SURPLUS_WATER_DEPTH, M1.FULL_LOAD_WATER, M1.EMPTY_LOAD_WATER, M1.HEADER_COCKPIT_DISTANCE, M1.STATUS, J.NM AS STATUS_LABEL, M1.CREATE_BY, M1.CREATE_BY_NAME, M1.CREATE_TIME, M1.UPDATE_BY, M1.UPDATE_BY_NAME, M1.UPDATE_TIME, M1.BO_HAI_TONG_ID, M1.CERTIFICATE_PATH, M1.APPLICATION_UNIT, M1.APPLICATION_UNIT_CODE, M1.IS_FOCUS_SHIP, M1.IS_BLACK_SHIP FROM M_SHIP_BLACK M1 left join M_DICT_DATA d ON M1.SHIP_TYPE_CODE=d.DICT_VALUE and d.DICT_TYPE='SHIP_TYPE' left join M_DICT_DATA e ON M1.SHIP_KIND_CODE=e.DICT_VALUE and e.DICT_TYPE='SHIP_KIND' left join M_DICT_DATA f ON M1.NATION_CODE=f.DICT_VALUE and e.DICT_TYPE='NATION' left join m_constants j on M1.STATUS = j.cd and j.TYPE_CD = 'SHIP_STATUS'
and (FUNC_SHIP_NAME_REPLACE(M1.SHIP_NAME) LIKE #{shipName} OR M1.SHORTHAND_CODE LIKE #{shipName})
and M1.SHIP_NAME_EN = #{shipNameEn}
and M1.SHIP_KIND_CODE = #{shipKindCode}
and M1.NATION_CODE = #{nationCode}
and M1.SHIP_TYPE_CODE = #{shipTypeCode}
and M1.IMO = #{imo}
and M1.MMSI = #{mmsi}
and M1.CALL_NO = #{callNo}
and M1.STATUS = #{status}

mapper.select:
select *
from M_SHIP
where (STATUS != '0' AND  STATUS IS NOT NULL )

    and SHIP_NAME = #{shipName,jdbcType=VARCHAR}


    and IMO = #{imo,jdbcType=VARCHAR}


    and MMSI =#{mmsi,jdbcType=VARCHAR}

mapper.update:
UPDATE M_SHIP_BLACK
SHIP_NAME = #{shipName,jdbcType=VARCHAR}, SHIP_NAME_EN = #{shipNameEn,jdbcType=VARCHAR}, SHORTHAND_CODE = #{shorthandCode,jdbcType=VARCHAR}, SHIP_KIND_CODE = #{shipKindCode,jdbcType=VARCHAR}, NATION_CODE = #{nationCode,jdbcType=VARCHAR}, SHIP_TYPE_CODE = #{shipTypeCode,jdbcType=VARCHAR}, IMO = #{imo,jdbcType=VARCHAR}, MMSI = #{mmsi,jdbcType=VARCHAR}, CALL_NO = #{callNo,jdbcType=VARCHAR}, SHIP_LENGTH = #{shipLength,jdbcType=DECIMAL}, SHIP_WIDTH = #{shipWidth,jdbcType=DECIMAL}, SHIP_HEIGHT = #{shipHeight,jdbcType=DECIMAL}, SELF_WEIGHT = #{selfWeight,jdbcType=DECIMAL}, NET_WEIGHT = #{netWeight,jdbcType=DECIMAL}, TOTAL_WEIGHT = #{totalWeight,jdbcType=DECIMAL}, HATCH_NUM = #{hatchNum,jdbcType=INTEGER}, CABIN_LAYER_NUM = #{cabinLayerNum,jdbcType=INTEGER}, DWT = #{dwt,jdbcType=DECIMAL}, CABIN_VOLUME = #{cabinVolume,jdbcType=DECIMAL}, HATCH_SIZE = #{hatchSize,jdbcType=VARCHAR}, MAX_SPEED = #{maxSpeed,jdbcType=DECIMAL}, SPEED = #{speed,jdbcType=DECIMAL}, MOULDED_DEPTH = #{mouldedDepth,jdbcType=DECIMAL}, HANGER_NUM = #{hangerNum,jdbcType=INTEGER}, CABIN_TYPE = #{cabinType,jdbcType=VARCHAR}, HANGER_LOAD = #{hangerLoad,jdbcType=VARCHAR}, HATCH_COVER_TYPE_CODE = #{hatchCoverTypeCode,jdbcType=VARCHAR}, HANGER_LOCATION = #{hangerLocation,jdbcType=VARCHAR}, CAPTAIN_PHONE = #{captainPhone,jdbcType=VARCHAR}, CAPTAIN_NAME = #{captainName,jdbcType=VARCHAR}, BUILT_YM = #{builtYm,jdbcType=VARCHAR}, WATER_VOLUME = #{waterVolume,jdbcType=DECIMAL}, SURPLUS_WATER_DEPTH = #{surplusWaterDepth,jdbcType=DECIMAL}, FULL_LOAD_WATER = #{fullLoadWater,jdbcType=DECIMAL}, EMPTY_LOAD_WATER = #{emptyLoadWater,jdbcType=DECIMAL}, HEADER_COCKPIT_DISTANCE = #{headerCockpitDistance,jdbcType=DECIMAL}, STATUS = #{status,jdbcType=VARCHAR}, IS_FOCUS_SHIP = #{isFocusShip,jdbcType=VARCHAR}, IS_BLACK_SHIP = #{isBlackShip,jdbcType=VARCHAR}, IDEA = #{idea,jdbcType=VARCHAR}, APPROVAL_BY = #{approvalBy,jdbcType=BIGINT}, APPROVAL_NAME = #{approvalName,jdbcType=VARCHAR}, APPROVAL_TIME = #{approvalTime,jdbcType=DATE}, CERTIFICATE_PATH = #{certificatePath,jdbcType=VARCHAR}, APPLICATION_UNIT = #{applicationUnit,jdbcType=VARCHAR}, APPLICATION_UNIT_CODE = #{applicationUnitCode,jdbcType=BIGINT}, UPDATE_BY = #{loginUserId, jdbcType=BIGINT}, UPDATE_BY_NAME = #{loginUserName, jdbcType=VARCHAR}, UPDATE_TIME = #{now}
ID = #{id}
